import pika
import json

# Create connection to RabbitMQ server
def get_rabbit_connection():
    credentials = pika.PlainCredentials('guest', 'guest')
    connection = pika.BlockingConnection(pika.ConnectionParameters(host='localhost', port=5672, credentials=credentials))
    return connection

# Create a channel for sending messages
def create_channel(connection):
    channel = connection.channel()
    channel.queue_declare(queue='tasks_queue')
    return channel

# Function to send task message using publisher
def publish_task(channel, task_name):
    message = {'task': task_name}
    message_json = json.dumps(message)
    channel.basic_publish(exchange='',
                          routing_key='tasks_queue',
                          body=message_json)

# Consumer function that processes incoming messages
def consume_tasks(connection):
    channel = connection.channel()
    channel.queue_declare(queue='tasks_queue')
    
    def callback(ch, method, properties, body):
        task_name = json.loads(body)['task']
        print(f'Received {task_name} for processing...')

    channel.basic_consume(callback,
                          queue='tasks_queue',
                          no_ack=True)
    print('Waiting for tasks...')
    channel.start_consuming()

# Main program
if __name__ == '__main__':
    connection = get_rabbit_connection()
    
    # Publisher example usage
    channel = create_channel(connection)
    publish_task(channel, 'example_task')
    connection.close()

    # Consumer example usage
    consume_tasks(get_rabbit_connection())